// Grab the bundled data array from the incoming item
let articles = $input.first().json.data; 

// Start building our clean email/message text
let alertMessage = "Business Risk Alert \n\n";

// Loop through each bundled article
for (let item of articles) {
    try {
        // Unpack the text string back into a real JSON object
        let aiData = JSON.parse(item.output);

        // Extract our specific pieces of information
        let riskLevel = aiData.Risk_Level;
        let riskAnalysis = aiData.Reason;

        // Add them neatly to our final message
        alertMessage += `Risk Level: ${riskLevel}\n`;
        alertMessage += `Risk Analysis: ${riskAnalysis}\n`;
        alertMessage += `-----------------------------------\n\n`;

    } catch (error) {
        // Just in case the AI ever formats the text weirdly and it can't be parsed
        alertMessage += `Error reading AI output for one article.\n\n`;
    }
}

// Output the final, beautifully formatted text message
return [{ 
    json: { 
        formatted_message: alertMessage 
    } 
}];
